-- Converted from MySQL dump for Supabase/Postgres

BEGIN;

DROP TABLE IF EXISTS public."t_Group";

CREATE TABLE public."t_Group" (
  id integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "Group_Title" varchar(100),
  "NFRCode" text,
  "SourceName" text,
  "ActivityName" text
);



SELECT setval(
  pg_get_serial_sequence('public."t_Group"', 'id'),
  COALESCE((SELECT MAX(id) FROM public."t_Group"), 1),
  true
);

COMMIT;

-- Supabase RLS: read-only access for anon/authenticated
ALTER TABLE public."t_Group" ENABLE ROW LEVEL SECURITY;
ALTER TABLE public."t_Group" FORCE ROW LEVEL SECURITY;

REVOKE ALL ON TABLE public."t_Group" FROM anon, authenticated;
GRANT SELECT ON TABLE public."t_Group" TO anon, authenticated;

DROP POLICY IF EXISTS t_group_read ON public."t_Group";
CREATE POLICY t_group_read
ON public."t_Group"
FOR SELECT
TO anon, authenticated
USING (true);
